INSERT INTO position_categories (id, positionId, name) VALUES (1, 6, 'Görev Bilinci');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (1, '1', 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (1, '2', 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (1, '3', 'İşine, kuruma ve kendisine sunulan kaynaklara zarar verecek hiçbir davranış sergilemez.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (1, '4', 'Ahlaki ve etik değerlere uygun davranır. Davranışlarının sorumluluğunu üstlenir.');
INSERT INTO position_categories (id, positionId, name) VALUES (2, 6, 'İletişim Becerisi');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (2, '5', 'Karşındakini dinler ve verilmek istenen mesajı doğru bir şekilde anlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (2, '6', 'Söylemek istediklerini, açık, kısa ve net bir biçimde karşı tarafa aktarır. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (2, '7', 'İşle ilgili konularla ilgili bilgiyi zamanında aktarır ve paylaşır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (2, '8', 'Her türlü iletişimde empati kurmaya özen gösterir.Gerektiğinde iletişim tarzını değiştirebilir.');
INSERT INTO position_categories (id, positionId, name) VALUES (3, 6, 'Analitik Düşünme ve Problem Çözme');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (3, '9', 'Gelişmekte olan problemleri görür, önleyici davranış geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (3, '10', 'Durum ve problem karşısında alacağı hareketin sonucunu bilir. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (3, '11', 'Mevcut sorunu gidermek için alternatif çözüm yolları geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (3, '12', 'Benzer sorunlar arasında ilişki kurar; geçmişteki deneyimlerden faydalanır.');
INSERT INTO position_categories (id, positionId, name) VALUES (4, 6, 'Kalite Odaklılık');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, '13', 'Mevcut düzen ve iş yapma yöntemine uygun çalışır. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, '14', 'Kaliteyi belirlenen standartlara göre uyarlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, '15', 'İş yapma yöntemini sürekli geliştirmeye, verimlilik ve etkililiği artırmaya odaklı çalışır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, '16', 'İş yapma yöntemine ilişkin akış ve prosedürlerdeki yeniliklere adapte olur.');

